mapper.select:
SELECT id, request_id, community_id, operator_id, operator_name, operator_role,
       operator_ip, operation_type, operation_time, target_type, target_id,
       before_value, after_value, operation_result, error_message, create_time
FROM sys_operation_log
WHERE 1=1

    AND community_id = #{communityId}


    AND operator_id = #{operatorId}


    AND operation_type = #{operationType}


    AND operation_time >= #{startTime}


    AND operation_time <= #{endTime}

ORDER BY operation_time DESC
LIMIT 100
